// Define a structure to hold the count of numbers
typedef struct {
    int count;
    int threshold;
} CountInfo;

// Function to count occurrences of each number in the input list
void countOccurrences(int *numbers, int size, CountInfo *count) {
    for (int i = 0; i < size; i++) {
        count[numbers[i]] = 0;
    }
}

// Function to remove duplicates based on a threshold
int *remove_duplicates(int *numbers, int size, int threshold) {
    // Allocate memory for the result
    int *result = (int *)malloc(size * sizeof(int));
    if (result == NULL) {
        return NULL; // Memory allocation failed
    }

    // Allocate memory for the count structure
    CountInfo *count = (CountInfo *)malloc(sizeof(CountInfo));
    if (count == NULL) {
        free(result);
        return NULL; // Memory allocation failed
    }

    // Initialize the count structure
    count->count = 0;
    count->threshold = threshold;

    // Count the occurrences of each number
    countOccurrences(numbers, size, count);

    // Initialize the result array
    for (int i = 0; i < size; i++) {
        result[i] = -1; // Initialize to -1 to indicate not yet processed
    }

    // Process each number in the input list
    for (int i = 0; i < size; i++) {
        int num = numbers[i];
        if (count->count[num] <= count->threshold) {
            result[count->count[num]] = num;
            count->count[num] = count->threshold + 1; // Mark as processed
        }
    }

    // Return the result array
